    font-weight: 400;
    line-height: 1.10;
    letter-spacing: -0.02em;
  }

  /* Feature heading — 40px Matter */
  .text-feature {
    font-family: var(--font-matter);
    font-size: clamp(1.75rem, 3vw, 2.5rem);
    font-weight: 400;
    line-height: 1.10;
    letter-spacing: -0.015em;
  }

  /* Card title — 22px Matter Medium */
  .text-card {
